// Generated by AI (UnitTest MCP)
import { execFileSync, spawnSync } from "node:child_process";
import { mkdtempSync, mkdirSync, rmSync, writeFileSync } from "node:fs";
import { tmpdir } from "node:os";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

import { afterEach, describe, expect, it } from "vitest";

const publisher = join(
  dirname(fileURLToPath(import.meta.url)),
  "../../../scripts/canonical-push.mjs"
);
const temporaryDirectories = [];

afterEach(() => {
  for (const directory of temporaryDirectories.splice(0)) {
    rmSync(directory, { recursive: true, force: true });
  }
});

const git = (cwd, args) =>
  execFileSync("git", args, { cwd, encoding: "utf8", stdio: "pipe" }).trim();

const commitFile = (repo, name, content, message) => {
  writeFileSync(join(repo, name), content);
  git(repo, ["add", "--", name]);
  git(repo, ["commit", "-m", message]);
};

const sandbox = () => {
  const root = mkdtempSync(join(tmpdir(), "mindleak-canonical-push-"));
  temporaryDirectories.push(root);
  const remote = join(root, "remote.git");
  const repo = join(root, "repo");
  mkdirSync(repo);
  git(root, ["init", "--bare", remote]);
  git(repo, ["init", "-b", "main"]);
  git(repo, ["config", "user.name", "Canonical Push Test"]);
  git(repo, ["config", "user.email", "canonical-push@example.invalid"]);
  commitFile(repo, "README.md", "initial\n", "initial");
  git(repo, ["remote", "add", "origin", remote]);
  git(repo, ["push", "-u", "origin", "main"]);
  return { root, remote, repo };
};

const runPublisher = (repo, args = [], env = process.env) =>
  spawnSync(process.execPath, [publisher, ...args], {
    cwd: repo,
    encoding: "utf8",
    env,
  });

describe("canonical-push", () => {
  it("refuses direct publication from main", () => {
    const { repo } = sandbox();

    const result = runPublisher(repo);

    expect(result.status).toBe(2);
    expect(result.stderr).toMatch(/direct protected-branch publication is forbidden/);
  }, 30_000);

  it("refuses publication while the shared index has staged changes", () => {
    const { repo } = sandbox();
    git(repo, ["checkout", "-b", "fleet/staged"]);
    writeFileSync(join(repo, "staged.txt"), "not committed\n");
    git(repo, ["add", "--", "staged.txt"]);

    const result = runPublisher(repo);

    expect(result.status).toBe(2);
    expect(result.stderr).toMatch(/shared index contains staged changes/);
  }, 30_000);

  it("allows the pre-push hook only through the canonical publisher", () => {
    const { repo } = sandbox();
    git(repo, ["checkout", "-b", "fleet/guarded"]);

    const direct = runPublisher(repo, ["--verify-pre-push"]);
    const canonical = runPublisher(repo, ["--verify-pre-push"], {
      ...process.env,
      MINDLEAK_CANONICAL_PUBLISH: "1",
    });

    expect(direct.status).toBe(2);
    expect(direct.stderr).toMatch(/pushes must run through/);
    expect(canonical.status, canonical.stderr).toBe(0);
  }, 30_000);

  it("refuses publication when the remote branch is not an ancestor", () => {
    const { root, remote, repo } = sandbox();
    const peer = join(root, "peer");
    git(repo, ["checkout", "-b", "fleet/diverged"]);
    commitFile(repo, "base.txt", "base\n", "fleet base");
    git(repo, ["push", "-u", "origin", "fleet/diverged"]);

    git(root, ["clone", remote, peer]);
    git(peer, ["config", "user.name", "Peer"]);
    git(peer, ["config", "user.email", "peer@example.invalid"]);
    git(peer, ["checkout", "fleet/diverged"]);
    commitFile(peer, "remote.txt", "remote\n", "remote advance");
    git(peer, ["push", "origin", "fleet/diverged"]);

    commitFile(repo, "local.txt", "local\n", "local advance");
    const result = runPublisher(repo);

    expect(result.status).toBe(2);
    expect(result.stderr).toMatch(/is not an ancestor of HEAD/);
  }, 30_000);

  it("publishes the current fleet branch's exact HEAD", () => {
    const { root, remote, repo } = sandbox();
    git(repo, ["checkout", "-b", "fleet/canonical"]);
    commitFile(repo, "feature.txt", "feature\n", "fleet feature");
    const expected = git(repo, ["rev-parse", "HEAD"]);

    const result = runPublisher(repo);

    expect(result.status, result.stderr).toBe(0);
    expect(result.stdout).toMatch(/published HEAD -> origin\/fleet\/canonical/);
    expect(git(root, ["--git-dir", remote, "rev-parse", "refs/heads/fleet/canonical"])).toBe(
      expected
    );
  }, 30_000);
});
